import Link from "next/link";

// assets
import { Chrome, Facebook, Globe, Instagram } from "lucide-react";

// project
import branding from "@/branding.json";

// constants
const footerLinks = [
  { label: "About Us", href: "#" },
  { label: "Services", href: "#" },
  { label: "Privacy", href: "#" },
  { label: "Content", href: "#" }
];

const socialLinks = [
  { icon: Facebook, href: "#" },
  { icon: Chrome, href: "#" },
  { icon: Instagram, href: "#" }
];

//  ------------------------------ | FOOTER - 10 | ------------------------------  //

export default function Footer10() {
  return (
    <footer className="py-12 md:py-20">
      <div className="container px-4 mx-auto">
        <div className="grid grid-cols-12 gap-y-6 items-center">
          {/* Brand Section */}
          <div className="col-span-12 md:col-span-3 flex items-center justify-center md:justify-start gap-2">
            <Globe className="h-5 w-5 text-slate-400" />
            <span className="text-md font-medium text-slate-500">
              {branding.brandName} UI Kit
            </span>
          </div>

          {/* Navigation Links */}
          <div className="col-span-12 md:col-span-6">
            <nav className="flex flex-wrap items-center justify-center gap-x-6">
              {footerLinks.map((link) => (
                <Link
                  key={link.label}
                  href={link.href}
                  className="text-md text-slate-500 hover:text-primary transition-colors"
                >
                  {link.label}
                </Link>
              ))}
            </nav>
          </div>

          {/* Social Icons Section */}
          <div className="col-span-12 md:col-span-3 flex items-center justify-center md:justify-end gap-6">
            {socialLinks.map((social, index) => (
              <Link
                key={index}
                href={social.href}
                className="text-slate-400 hover:text-primary transition-colors"
                aria-label="Social link"
              >
                <social.icon size={20} strokeWidth={1.5} />
              </Link>
            ))}
          </div>
        </div>
      </div>
    </footer>
  );
}
